-- Migration 199: Kid-friendly word list for workflow password generation.
-- Words are stored ONLY in this database table and are never exposed via the
-- web UI or any API endpoint. The service reads this table at runtime and
-- caches the words in memory for the lifetime of the process.
-- Idempotent: INSERT IGNORE silently skips words that already exist.

CREATE TABLE IF NOT EXISTS workflow_kid_friendly_words (
    id    INT AUTO_INCREMENT PRIMARY KEY,
    word  VARCHAR(64) NOT NULL,
    UNIQUE KEY uq_workflow_kid_friendly_words_word (word)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

